-    JSON.stringify({
-      type: "req",
-      id: params.id,
-      method: "connect",
-      params: {
-        minProtocol: PROTOCOL_VERSION,
-        maxProtocol: PROTOCOL_VERSION,
-        client: TEST_OPERATOR_CLIENT,
-        caps: [],
-        role: "operator",
-        auth: params.token ? { token: params.token } : undefined,
-        device: params.device,
